export function parseArgs(argv) {
  const result = { _: [] }
  let i = 0
  while (i < argv.length) {
    const arg = argv[i]
    if (!arg.startsWith('--')) {
      result._.push(arg)
      i += 1
    } else if (arg.includes('=')) {
      const eqIndex = arg.indexOf('=')
      const key = arg.slice(0, eqIndex)
      const value = arg.slice(eqIndex + 1)
      result[key] = value
      i += 1
    } else {
      const key = arg.slice(2)
      i += 1
      if (i < argv.length && !argv[i].startsWith('-')) {
        result[key] = argv[i]
        i += 1
      } else {
        result[key] = true
      }
    }
  }
  return result
}

